-- ═══════════════════════════════════════════════════════════════════
-- CodeQuest · Migración 015 — SQL con Oracle · m3a: Modelado avanzado
-- ═══════════════════════════════════════════════════════════════════
-- Cubre el resto de la Parte II (arcos/OR exclusivo, jerarquías,
-- recursivas, supertipos/subtipos con herencia, exhaustividad,
-- exclusividad/superposición) y la Parte IV COMPLETA (histórico:
-- auditoría, logging/journaling, fecha vs entidad DÍA, tiempo en el
-- UID, historiales, intersección histórica, no transferibilidad
-- condicionada por el tiempo).
-- Diagramas 4.1 (arco EVENTO) y 5.1 (M:M histórica JOYA–ESTRELLA)
-- con NetworkDiagram data-driven.
-- Precisiones vinculantes: arco ≠ relación identificadora (barra);
-- subtipos totales/parciales y disjuntos/superpuestos.
-- Reglas de contenido: quizzes autocontenidos o con términos técnicos.
-- OJO: SQL con Oracle está PUBLICADO — esta migración sale en vivo.
-- Idempotente: borra y recrea las lecciones de ESTE módulo.
-- Ejecutar DESPUÉS de 011 (estructura v2).
-- ═══════════════════════════════════════════════════════════════════

-- Limpia el módulo (cascade borra sus content_blocks)
delete from public.lessons
where module_id = (
  select m.id
  from public.modules m
  join public.courses c on c.id = m.course_id
  where c.slug = 'sql-oracle' and m.slug = 'm3a-modelado-avanzado'
);

-- ── Lecciones del módulo ──────────────────────────────────────────────
insert into public.lessons (module_id, slug, title, kind, xp, sort_order)
select m.id, v.slug, v.title, v.kind, v.xp, v.ord
from public.modules m
join public.courses c on c.id = m.course_id,
     (values
       ('m3a-l01-arcos',              'Arcos: el OR exclusivo',              'leccion',  20, 1),
       ('m3a-l02-jerarquias-recursion','Jerarquías y recursión',             'leccion',  20, 2),
       ('m3a-l03-supertipos',         'Supertipos y subtipos',               'leccion',  20, 3),
       ('m3a-l04-tiempo',             'El tiempo entra al modelo',           'leccion',  20, 4),
       ('m3a-l05-historiales',        'Historiales: el tiempo en el UID',    'leccion',  20, 5),
       ('m3a-l06-practica-avanzado',  'Práctica: la hoja de estructuras',    'practica', 20, 6),
       ('m3a-x01-examen',             'Examen: Modelado avanzado',           'examen',   40, 7)
     ) as v(slug, title, kind, xp, ord)
where c.slug = 'sql-oracle' and m.slug = 'm3a-modelado-avanzado';

-- ═════════════════════════════════════════════════════════════════════
-- L01 · Arcos: el OR exclusivo (+ Diagrama 4.1)
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"Uno de estos, pero solo uno","body":"Algunas reglas de negocio dicen 'O esto O aquello, nunca ambos': un EVENTO se celebra en una CASA PRIVADA o en un ESPACIO PÚBLICO — siempre en uno, jamás en los dos. Un ESTUDIO de laboratorio del hospital se procesa en el LABORATORIO PROPIO o en un LABORATORIO EXTERNO. Esa restricción de OR EXCLUSIVO se dibuja con un ARCO: una curva que abraza las relaciones alternativas de la entidad, declarando 'de estas relaciones, exactamente una por instancia'. Cada relación bajo el arco es individualmente OPCIONAL (la o del módulo 1)… pero el arco obliga a que UNA se cumpla. La regla de diseño del oficio: prefiere el arco sobre los subtipos (próxima lección) cuando las entidades alternativas NO comparten atributos significativos — una casa y una plaza no se parecen en nada; forzarlas a un supertipo sería inventar parentescos."}$j$),
  (2, 'diagrama', $j${"title":"Diagrama 4.1 · El arco en acción","component":"NetworkDiagram","props":{"label":"EVENTO se celebra en UNO de dos lugares (OR exclusivo)","ancho":520,"alto":320,"grupos":[{"id":"arco","x":14,"y":170,"w":492,"h":130,"titulo":"⌒ ARCO — exactamente una de estas relaciones","descripcion":"El arco abraza las relaciones alternativas: cada EVENTO se conecta con UNA de las dos entidades — nunca ambas, nunca ninguna. Las relaciones son opcionales una a una; el arco las vuelve obligatorias en conjunto y excluyentes entre sí."}],"nodos":[{"id":"evento","x":160,"y":30,"w":200,"h":52,"titulo":"EVENTO","subtitulo":"# evento_id · * fecha","descripcion":"La entidad con la disyuntiva: todo evento se celebra en algún lugar — pero el modelo ofrece dos tipos de lugar sin parentesco entre sí."},{"id":"casa","x":40,"y":210,"w":200,"h":52,"titulo":"CASA PRIVADA","subtitulo":"# casa_id · * direccion","descripcion":"Primera alternativa. Nota que sus atributos (dirección, propietario…) no se parecen a los del espacio público: por eso arco y no supertipo."},{"id":"espacio","x":280,"y":210,"w":200,"h":52,"titulo":"ESPACIO PÚBLICO","subtitulo":"# espacio_id · * aforo","descripcion":"Segunda alternativa, con atributos propios (aforo, permisos municipales…). Sin atributos comunes significativos: el arco es la elección correcta."}],"enlaces":[{"de":"evento","a":"casa","tipo":"flecha","etiqueta":"o en…","descripcion":"Relación individualmente opcional: este evento PUEDE celebrarse en una casa privada."},{"de":"evento","a":"espacio","tipo":"flecha","etiqueta":"o en…","descripcion":"…o en un espacio público. El arco (el marco punteado) exige exactamente UNA de las dos."}],"hint":"Toca el marco del arco y cada entidad."},"caption":"El arco = OR exclusivo: de las relaciones abrazadas, exactamente una por instancia. En el físico se implantará con dos FKs opcionales y una CHECK que vigile que solo una tenga valor — el módulo de mapeo lo hará contigo."}$j$),
  (3, 'texto', $j${"title":"Arco no es barra: la confusión que cuesta exámenes","body":"Precisión que separa a quien entiende de quien memoriza: el ARCO y la BARRA (|) del módulo 2 son cosas distintas que a veces se confunden porque ambas se dibujan sobre relaciones. La BARRA es una relación IDENTIFICADORA: dice 'esta relación forma parte de mi UID — te necesito para tener identidad' (CUENTA necesita a BANCO). El ARCO es una relación EXCLUYENTE: dice 'de estas alternativas, elijo exactamente una' (EVENTO elige casa o plaza). Una habla de IDENTIDAD; el otro, de ELECCIÓN. Pueden incluso convivir en la misma entidad — un evento identificado por su relación con el lugar elegido — pero cada símbolo declara su propia regla. En una entrevista o un examen de certificación, confundirlos delata al que estudió dibujos sin estudiar significados."}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"En un ERD, un ARCO que abraza dos relaciones de la entidad EVENTO declara que…","options":["Ambas relaciones son obligatorias a la vez","De esas relaciones, cada evento cumple EXACTAMENTE UNA: un OR exclusivo","Las relaciones están prohibidas","El UID de EVENTO es compuesto"],"correctIndex":1,"feedback":{"correct":"Correcto. Una sí, la otra no — y siempre alguna: el OR exclusivo del modelado.","incorrect":"El arco es la restricción OR exclusiva: de las relaciones abrazadas, exactamente una por instancia."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Cuándo prefiere el oficio un ARCO en lugar de modelar con supertipos y subtipos?","options":["Siempre: los arcos son más modernos","Cuando las entidades alternativas NO comparten atributos significativos (una casa y una plaza no se parecen): forzar un supertipo inventaría parentescos","Cuando hay más de diez entidades","Nunca: los arcos están obsoletos"],"correctIndex":1,"feedback":{"correct":"Correcto. Sin atributos comunes, no hay herencia que aprovechar: el arco expresa la disyuntiva sin fingir familia.","incorrect":"La regla de diseño: entidades sin atributos comunes significativos → arco; con herencia real → supertipo/subtipos."}}$j$),
  (6, 'quiz', $j${"variant":"multiple_choice","prompt":"Precisión de examen: ¿en qué se diferencian el ARCO y la BARRA (|) dibujados sobre relaciones de un ERD?","options":["Son sinónimos","La barra es relación IDENTIFICADORA ('te necesito para mi UID'); el arco es relación EXCLUYENTE ('elijo exactamente una de estas'): identidad vs elección","El arco es para 1:1 y la barra para 1:N","La barra es un error de dibujo"],"correctIndex":1,"feedback":{"correct":"Correcto. Identidad (barra) vs elección (arco): dos reglas distintas que pueden incluso convivir.","incorrect":"Barra = la relación entra al UID (identidad). Arco = OR exclusivo entre relaciones (elección). Confundirlos delata memorización sin comprensión."}}$j$),
  (7, 'resumen', $j${"title":"Resumen — Arcos","points":["El ARCO declara un OR exclusivo: de las relaciones abrazadas, exactamente UNA por instancia.","Cada relación bajo el arco es opcional por sí sola; el arco las vuelve excluyentes y conjuntamente obligatorias.","Regla de diseño: arco cuando las alternativas NO comparten atributos significativos.","ARCO ≠ BARRA: elección (arco) vs identidad (barra identificadora del módulo 2).","En el físico: FKs opcionales + una CHECK que vigila que solo una tenga valor (módulo de mapeo)."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm3a-l01-arcos';

-- ═════════════════════════════════════════════════════════════════════
-- L02 · Jerarquías y recursión
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"Dos formas de modelar niveles","body":"'El presidente dirige a directores, que dirigen a gerentes, que dirigen a analistas.' ¿Cómo se modela esa escalera? Opción 1 — la JERARQUÍA EXPLÍCITA: una entidad por nivel (PRESIDENTE, DIRECTOR, GERENTE, ANALISTA) encadenadas 1:N. Es muy específica — cada nivel puede tener sus propios atributos — pero RÍGIDA: si la empresa inventa un nivel intermedio, hay que modificar el modelo entero. Opción 2 — la RELACIÓN RECURSIVA, apodada 'oreja de cerdo' por cómo se dibuja: la entidad EMPLEADO se relaciona CONSIGO MISMA — 'un empleado ES GESTIONADO POR otro empleado'. Una sola entidad, niveles infinitos, reorganizaciones sin tocar el modelo. Elegante y flexible… con una exigencia técnica que no se puede olvidar."}$j$),
  (2, 'diagrama', $j${"title":"La oreja de cerdo, desdoblada","component":"NetworkDiagram","props":{"label":"Relación recursiva: EMPLEADO gestiona a EMPLEADO","ancho":520,"alto":250,"grupos":[{"id":"misma","x":14,"y":30,"w":492,"h":200,"titulo":"UNA sola entidad — dos papeles","descripcion":"En el ERD real esto se dibuja como UNA caja EMPLEADO con una línea que sale y vuelve a ella misma (la 'oreja de cerdo'). Aquí la desdoblamos en sus dos papeles para que se lea la mecánica."}],"nodos":[{"id":"jefe","x":40,"y":80,"w":200,"h":56,"titulo":"EMPLEADO","subtitulo":"en su papel de jefe","descripcion":"La misma entidad EMPLEADO, jugando el papel de gestor. No es otra tabla ni otro tipo: es la misma caja del ERD."},{"id":"sub","x":280,"y":80,"w":200,"h":56,"titulo":"EMPLEADO","subtitulo":"en su papel de gestionado","descripcion":"El otro extremo de la MISMA entidad. En el físico: una FK jefe_id en EMPLEADO… apuntando a EMPLEADO."},{"id":"nota","x":120,"y":170,"w":280,"h":44,"titulo":"jefe_id es OPCIONAL (o)","tag":"la exigencia","descripcion":"Alguien está en la cima: la directora general no tiene jefe. Si la relación fuera obligatoria, la cadena no tendría dónde empezar — por eso los atributos del nivel superior deben ser opcionales."}],"enlaces":[{"de":"jefe","a":"sub","tipo":"flecha","etiqueta":"gestiona a (1:N)","descripcion":"Un jefe gestiona a muchos; cada empleado tiene a lo más UN jefe. La relación recursiva clásica."}],"hint":"Toca los dos papeles y la nota de la exigencia."},"caption":"Recursiva = la entidad se relaciona consigo misma. La exigencia: la relación debe ser OPCIONAL en la punta — alguien (la directora general) no tiene jefe."}$j$),
  (3, 'texto', $j${"title":"Cuál elegir (y la exigencia de la recursiva)","body":"La decisión es un intercambio clásico. JERARQUÍA EXPLÍCITA cuando los niveles son POCOS, FIJOS y con atributos genuinamente distintos (un PRESIDENTE tiene atributos que un ANALISTA no). RECURSIVA cuando los niveles son variables o profundos y las instancias comparten naturaleza: todos son empleados, solo cambia quién reporta a quién. Y la exigencia técnica de la recursiva, que las entrevistas adoran: la relación DEBE ser opcional en la punta — si 'todo empleado tiene jefe' fuera obligatorio, ¿quién es el jefe de la directora general? La cadena necesita un inicio sin jefe, así que jefe_id nace opcional (la o del módulo 1). En el hospital: MEDICO supervisado por MEDICO (residentes y adscritos) — recursiva de manual, con la jefa de servicio sin supervisor."}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"La entidad EMPLEADO se relaciona consigo misma ('es gestionado por'). Ese patrón se llama…","options":["Jerarquía explícita","Relación RECURSIVA (la 'oreja de cerdo'): una sola entidad, niveles infinitos","Arco","Dependencia transitiva"],"correctIndex":1,"feedback":{"correct":"Correcto. Una entidad, dos papeles: la solución elegante y flexible para niveles variables.","incorrect":"La entidad relacionada consigo misma es la relación recursiva — dibujada como una línea que sale y vuelve a la misma caja."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Por qué en una relación recursiva ('todo empleado es gestionado por un empleado') la relación DEBE ser opcional?","options":["Para ahorrar espacio","Porque alguien está en la cima: la directora general no tiene jefe — sin la opcionalidad, la cadena no tendría inicio posible","Porque Oracle no permite FKs obligatorias","No debe ser opcional"],"correctIndex":1,"feedback":{"correct":"Correcto. La exigencia técnica de la recursiva: la punta de la pirámide existe sin superior.","incorrect":"Si fuera obligatoria, ¿quién es el jefe del jefe supremo? La recursión exige atributos de nivel superior opcionales."}}$j$),
  (6, 'quiz', $j${"variant":"multiple_choice","prompt":"Los niveles de una organización son pocos, fijos, y cada uno tiene atributos genuinamente distintos. ¿Jerarquía explícita o recursiva?","options":["Recursiva siempre","JERARQUÍA EXPLÍCITA: una entidad por nivel — específica y clara cuando los niveles no cambian y difieren de verdad","Un arco","Ninguna: se usa una lista"],"correctIndex":1,"feedback":{"correct":"Correcto. El intercambio: explícita = específica pero rígida; recursiva = flexible cuando todos comparten naturaleza.","incorrect":"Niveles fijos + atributos distintos por nivel → jerarquía explícita. La recursiva brilla cuando los niveles varían y las instancias son de la misma especie."}}$j$),
  (7, 'resumen', $j${"title":"Resumen — Jerarquías y recursión","points":["Jerarquía EXPLÍCITA: una entidad por nivel, encadenadas 1:N — específica pero rígida.","Relación RECURSIVA ('oreja de cerdo'): la entidad consigo misma — una caja, niveles infinitos.","La exigencia de la recursiva: la relación es OPCIONAL en la punta (la directora general no tiene jefe).","Elegir: niveles fijos y distintos → explícita; niveles variables y misma naturaleza → recursiva.","En el físico, la recursiva será una FK que apunta a su propia tabla (jefe_id → EMPLEADO)."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm3a-l02-jerarquias-recursion';

-- ═════════════════════════════════════════════════════════════════════
-- L03 · Supertipos y subtipos
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"Similitudes arriba, diferencias abajo","body":"El PERSONAL del hospital: médicos, enfermeros, administrativos. Todos comparten nombre, fecha de contratación y correo… pero el médico tiene colegiatura y especialidad, y el enfermero tiene turno y área. Modelar tres entidades sueltas repite lo común; una sola entidad revuelve lo distinto. La solución: SUPERTIPO y SUBTIPOS. El supertipo PERSONAL concentra lo COMPARTIDO; los subtipos MEDICO y ENFERMERO agregan lo PROPIO. La regla de oro es la HERENCIA: todo atributo y toda relación del supertipo pertenece automáticamente a cada subtipo — el médico TIENE nombre y fecha de contratación sin repetirlos, porque ES un personal. Se dibuja como cajas anidadas: los subtipos viven dentro del cuadro del supertipo."}$j$),
  (2, 'texto', $j${"title":"Las reglas del reparto: exhaustividad y exclusividad","body":"Dos preguntas disciplinan todo diseño de subtipos. EXHAUSTIVIDAD: ¿los subtipos listados cubren TODOS los casos? La convención clásica exige que sí — y para lograrlo sin inventariar el universo, se agrega el subtipo OTRO como red de seguridad (PERSONAL: MEDICO, ENFERMERO, OTRO — el administrativo cae ahí hasta merecer caja propia). Cuando la cobertura es completa, la especialización es TOTAL; si se admite que una instancia viva solo como supertipo sin subtipo, es PARCIAL. EXCLUSIVIDAD: ¿una instancia pertenece a UN solo subtipo? El diseño clásico dice sí (DISJUNTOS: nadie es médico y enfermero a la vez)… pero la realidad a veces se SUPERPONE — en una escuela, una PERSONA puede ser ALUMNO y EMPLEADO simultáneamente. El modelo debe DECLARAR cuál de los cuatro sabores usa (total/parcial × disjunto/superpuesto): esa declaración es una regla de negocio, y el mapeo físico la cobrará distinto."}$j$),
  (3, 'quiz', $j${"variant":"multiple_choice","prompt":"En el diseño supertipo/subtipos, la HERENCIA significa que…","options":["Los subtipos se borran con el supertipo","Todo atributo y relación del SUPERTIPO pertenece automáticamente a cada subtipo: MEDICO tiene nombre porque ES un PERSONAL","Los subtipos comparten UID entre sí","El supertipo copia los atributos de los subtipos"],"correctIndex":1,"feedback":{"correct":"Correcto. Lo común se declara UNA vez arriba y baja gratis: esa es la ganancia del patrón.","incorrect":"La herencia baja: lo del supertipo es de todos los subtipos. Lo propio de cada subtipo se queda en su caja."}}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Para qué se agrega el subtipo OTRO en un diseño de subtipos?","options":["Por decoración","Para garantizar la EXHAUSTIVIDAD: los subtipos deben cubrir todos los casos, y OTRO es la red de seguridad para lo que no tiene caja propia","Para guardar los registros borrados","Para las instancias sin UID"],"correctIndex":1,"feedback":{"correct":"Correcto. La convención exige cobertura total: OTRO atrapa al administrativo hasta que merezca su propia caja.","incorrect":"OTRO existe por exhaustividad: todo caso real debe tener un subtipo donde caer."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"En una escuela, una PERSONA puede ser ALUMNO y EMPLEADO a la vez. En la clasificación de subtipos, esa especialización es…","options":["Disjunta (exclusiva)","SUPERPUESTA: una instancia puede pertenecer a varios subtipos simultáneamente — y el modelo debe declararlo, porque el mapeo físico cambia","Total","Un arco"],"correctIndex":1,"feedback":{"correct":"Correcto. Los cuatro sabores existen (total/parcial × disjunto/superpuesto) y declarar el correcto es una regla de negocio.","incorrect":"Pertenecer a varios subtipos a la vez = superposición. El clásico es disjunto, pero la realidad a veces se superpone — y se declara."}}$j$),
  (6, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Cuándo conviene supertipo/subtipos en lugar de un arco?","options":["Cuando las entidades no se parecen en nada","Cuando las alternativas COMPARTEN atributos y relaciones significativas: la herencia paga el patrón (PERSONAL arriba; lo propio de médico y enfermero abajo)","Siempre que haya más de dos entidades","Nunca: el arco siempre gana"],"correctIndex":1,"feedback":{"correct":"Correcto. El espejo de la regla del arco: con familia real, supertipo; sin parentesco, arco.","incorrect":"Subtipos cuando hay herencia que aprovechar (atributos comunes); arco cuando las alternativas no comparten nada significativo."}}$j$),
  (7, 'resumen', $j${"title":"Resumen — Supertipos y subtipos","points":["Supertipo = lo compartido; subtipos = lo propio. Se dibujan como cajas anidadas.","HERENCIA: atributos y relaciones del supertipo pertenecen automáticamente a cada subtipo.","EXHAUSTIVIDAD: los subtipos cubren todos los casos — el subtipo OTRO es la red de seguridad.","Sabores a declarar: TOTAL/PARCIAL (¿todos caen en un subtipo?) × DISJUNTO/SUPERPUESTO (¿solo uno a la vez?).","Subtipos con herencia real; arco sin parentesco. El mapeo físico de ambos: módulo siguiente."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm3a-l03-supertipos';

-- ═════════════════════════════════════════════════════════════════════
-- L04 · El tiempo entra al modelo
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"Del 'ahora' al registro histórico","body":"Todo lo modelado hasta aquí fotografía el AHORA: el salario actual, el precio vigente, el consultorio asignado hoy. Pero el negocio pregunta por el AYER: ¿cómo evolucionó el salario? ¿a qué precio se vendió en marzo? ¿qué médico ocupaba el consultorio cuando ocurrió el incidente? El MODELADO TEMPORAL convierte el presente en historia consultable, y sostiene tres necesidades del mundo real: el ANÁLISIS DE TENDENCIAS (comparar períodos), la VALORIZACIÓN y AMORTIZACIÓN de activos (cuánto valía entonces, cuánto se deprecia), y la AUDITORÍA: poder reconstruir qué valor tenía un dato cuando se tomó una decisión. Las técnicas: la ANOTACIÓN EN DIARIO (logging o journaling) — registrar cronológicamente el valor viejo ANTES de modificarlo — y los DATOS HISTÓRICOS como entidades propias, que verás en la próxima lección."}$j$),
  (2, 'texto', $j${"title":"¿Fecha como atributo… o entidad DÍA?","body":"La pregunta de diseño más fina del modelado temporal: ¿la fecha es un simple atributo (fecha_cita) o merece ser la entidad DÍA? El criterio es un viejo conocido — la 3FN. Si la fecha solo ubica el evento en el tiempo, es un atributo y punto. Pero si la fecha TIENE ATRIBUTOS PROPIOS — ese día fue festivo, hubo tarifa especial, la temperatura importó, era día de campaña de vacunación — entonces 'un atributo no puede tener atributos propios': la fecha es una entidad DÍA disfrazada, con su propio UID (la fecha misma) y sus atributos (es_festivo, tarifa, campaña), y las demás entidades se RELACIONAN con ella. El hospital que cobra tarifa especial los festivos no guarda es_festivo en cada cita (transitiva: 3FN violada) — crea DIA y las citas apuntan ahí."}$j$),
  (3, 'quiz', $j${"variant":"multiple_choice","prompt":"En términos de modelado temporal, ¿qué es la anotación en diario (logging/journaling)?","options":["Un tipo de índice","El registro CRONOLÓGICO de los valores viejos ANTES de modificarlos: la materia prima de la auditoría y la reconstrucción del pasado","Un respaldo semanal","Una vista de Oracle"],"correctIndex":1,"feedback":{"correct":"Correcto. Antes de pisar el valor, se anota: quién, cuándo, qué había. Sin eso, el pasado es irrecuperable.","incorrect":"Logging/journaling = anotar el valor anterior con su momento, antes del cambio. Así se reconstruyen decisiones y tendencias."}}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"El hospital cobra tarifa especial los días festivos y en días de campaña. ¿La fecha debe modelarse como atributo o como entidad DÍA, y por qué?","options":["Atributo: las fechas nunca son entidades","Entidad DÍA: la fecha tiene ATRIBUTOS PROPIOS (es_festivo, tarifa, campaña) — guardarlos en cada cita sería una dependencia transitiva (3FN)","Atributo, pero duplicado en cada tabla","Da igual"],"correctIndex":1,"feedback":{"correct":"Correcto. 'Un atributo no puede tener atributos propios': la fecha con vida propia es la entidad DÍA.","incorrect":"El criterio es la 3FN: fecha que solo ubica = atributo; fecha con atributos propios (festivo, tarifa) = entidad DÍA."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Cuáles son las tres necesidades de negocio que justifican el modelado temporal?","options":["Velocidad, espacio y estética","Análisis de TENDENCIAS, VALORIZACIÓN/AMORTIZACIÓN de activos y AUDITORÍA (reconstruir qué valor regía al decidir)","Backups, réplicas y clones","Ninguna: el presente basta"],"correctIndex":1,"feedback":{"correct":"Correcto. Comparar períodos, valorar activos en el tiempo y auditar decisiones: por eso el pasado se modela.","incorrect":"Tendencias + valorización/amortización + auditoría: las tres razones por las que el 'ahora' no basta."}}$j$),
  (6, 'resumen', $j${"title":"Resumen — El tiempo entra al modelo","points":["El modelo del 'ahora' no responde por el ayer: tendencias, valorización/amortización y auditoría exigen historia.","Logging/journaling: anotar cronológicamente el valor viejo ANTES de modificarlo.","Fecha que solo ubica = atributo; fecha con atributos propios (festivo, tarifa) = entidad DÍA.","El criterio para DÍA es la 3FN: 'un atributo no puede tener atributos propios'.","Los historiales como entidades (salarios, precios, asignaciones): la próxima lección."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm3a-l04-tiempo';

-- ═════════════════════════════════════════════════════════════════════
-- L05 · Historiales: el tiempo en el UID (+ Diagrama 5.1)
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"La receta del historial","body":"¿Cómo se guarda la evolución del salario sin pisar el valor anterior? Con una ENTIDAD HISTÓRICA: EMPLEADO 1:N HISTORIAL_SALARIO, donde cada instancia es un período — monto, fecha_inicio, fecha_fin (opcional: el período vigente aún no termina). Y aquí la clave técnica del módulo: EL TIEMPO ENTRA AL UID. ¿Qué identifica un registro del historial? No el empleado solo (tiene muchos períodos): empleado + fecha_inicio — un UID COMPUESTO donde la relación aporta la barra (módulo 2) y la FECHA completa la identidad. La misma receta sirve para el historial de PRECIOS de un producto y el historial de ASIGNACIONES (qué médico ocupó qué consultorio y cuándo): entidad histórica, 1:N con su dueño, tiempo en el UID."}$j$),
  (2, 'diagrama', $j${"title":"Diagrama 5.1 · La M:M con memoria","component":"NetworkDiagram","props":{"label":"PIEZA DE JOYERÍA alquilada por ESTRELLAS: la intersección histórica","ancho":520,"alto":330,"nodos":[{"id":"joya","x":24,"y":40,"w":200,"h":52,"titulo":"PIEZA DE JOYERÍA","subtitulo":"# pieza_id · * descripcion","descripcion":"Una joya se alquila a muchas estrellas a lo largo del tiempo. La relación con ESTRELLA es M:M… pero con historia."},{"id":"estrella","x":296,"y":40,"w":200,"h":52,"titulo":"ESTRELLA DE CINE","subtitulo":"# estrella_id · * nombre","descripcion":"Una estrella alquila muchas joyas. El M:M clásico del módulo 1 pediría una entidad asociativa — y el tiempo la vuelve histórica."},{"id":"hist","x":130,"y":170,"w":260,"h":92,"titulo":"HISTORIAL DE ALQUILERES","subtitulo":"| pieza · | estrella · # fecha_inicio · o fecha_fin","tag":"intersección","descripcion":"La entidad de intersección HISTÓRICA: cada instancia es UN alquiler concreto. Su UID compuesto: las dos relaciones (barras) + la FECHA — porque la misma estrella puede volver a alquilar la misma joya en otra ocasión: sin la fecha en el UID, ese segundo alquiler sería 'duplicado' imposible de registrar."}],"enlaces":[{"de":"joya","a":"hist","tipo":"flecha","etiqueta":"1:N","descripcion":"Una pieza aparece en muchos alquileres del historial."},{"de":"estrella","a":"hist","tipo":"flecha","etiqueta":"1:N","descripcion":"Una estrella aparece en muchos alquileres del historial."}],"hint":"Toca la entidad de intersección: su UID es la lección."},"caption":"La M:M del módulo 1 + el tiempo del módulo 4: la intersección histórica lleva las dos barras Y la fecha en su UID — así la misma pareja puede repetirse en fechas distintas."}$j$),
  (3, 'texto', $j${"title":"El tiempo también condiciona la transferibilidad","body":"Cierre del arco que abrimos en el módulo 2: la NO TRANSFERIBILIDAD CONDICIONADA POR EL TIEMPO. El turno del voluntario se reasigna… solo si no ha comenzado. La cita cambia de médico… solo mientras no esté atendida. El alquiler del diagrama se corrige… solo antes de la fecha de inicio. El patrón general: el ESTADO TEMPORAL de la instancia (¿ya ocurrió?) decide si la relación puede cambiar de manos. En el modelo se documenta como regla estructural condicionada; en el físico — lo verás en el curso — suele exigir apoyo de lógica adicional, porque una FK no sabe de calendarios. Es el ejemplo perfecto de cómo las piezas del curso se ensamblan: transferibilidad (módulo 2) + tiempo (este módulo) = una regla de negocio precisa y modelable."}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"En HISTORIAL_SALARIO (un empleado, muchos períodos), ¿qué compone el UID de cada registro y por qué?","options":["Solo empleado_id","empleado (la relación, con su barra) + fecha_inicio: el empleado solo no basta — tiene muchos períodos — y la FECHA completa la identidad","Solo el monto","Un UID artificial siempre, sin excepción"],"correctIndex":1,"feedback":{"correct":"Correcto. El tiempo entra al UID: relación + fecha identifican el período. (Un artificial también es válido — pero la fecha DEBE seguir siendo única por empleado.)","incorrect":"Cada empleado acumula períodos: identificarlos exige la relación MÁS la fecha de inicio — el tiempo como parte del UID."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"En la intersección histórica JOYA–ESTRELLA, ¿por qué la FECHA debe formar parte del UID además de las dos relaciones?","options":["Por decoración","Porque la MISMA pareja puede repetirse: la estrella que vuelve a alquilar la misma joya en otra fecha sería un 'duplicado' imposible de registrar sin el tiempo en el UID","Porque las fechas son obligatorias en Oracle","No debe: las dos FKs bastan siempre"],"correctIndex":1,"feedback":{"correct":"Correcto. Sin la fecha, el segundo alquiler de la misma pareja violaría la unicidad. El tiempo habilita la repetición legítima.","incorrect":"La pareja joya+estrella se repite en el tiempo: solo agregando la fecha al UID cada alquiler es único."}}$j$),
  (6, 'quiz', $j${"variant":"multiple_choice","prompt":"'La cita puede cambiar de médico solo mientras no esté atendida.' Ese patrón — el estado temporal decide si la relación cambia de manos — se llama…","options":["Dependencia funcional","NO TRANSFERIBILIDAD CONDICIONADA POR EL TIEMPO: transferible hasta que el evento ocurre, sellada después","Anomalía de actualización","Herencia parcial"],"correctIndex":1,"feedback":{"correct":"Correcto. Transferibilidad (módulo 2) + tiempo (este módulo): la regla condicionada que las FKs solas no saben vigilar.","incorrect":"Es la no transferibilidad condicionada por el tiempo: el '¿ya ocurrió?' decide si la conexión puede reasignarse."}}$j$),
  (7, 'resumen', $j${"title":"Resumen — Historiales","points":["Entidad histórica: 1:N con su dueño, cada instancia un período (monto, fecha_inicio, fecha_fin opcional).","EL TIEMPO ENTRA AL UID: relación (barra) + fecha identifican el período.","La receta sirve igual para salarios, precios y asignaciones.","Intersección HISTÓRICA (M:M + tiempo): las dos barras + la fecha en el UID — la pareja puede repetirse en fechas distintas.","No transferibilidad condicionada por el tiempo: el estado temporal decide si la relación cambia de manos."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm3a-l05-historiales';

-- ═════════════════════════════════════════════════════════════════════
-- L06 · Práctica: la hoja de estructuras (kind = practica)
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'ejercicio', $j${"scenario":"El hospital está modelando sus reglas complejas y te pasó la hoja de decisiones estructurales. El caso 1 viene resuelto de ejemplo; completa los demás con la estructura correcta (en minúsculas, tal como aparece en las opciones).","instructions":["Caso 2 — MEDICO es supervisado por otro MEDICO (residentes y adscritos; la jefa de servicio no tiene supervisor). ¿arco, recursiva o subtipos?","Caso 3 — PERSONAL se especializa en MEDICO, ENFERMERO y OTRO, compartiendo nombre y fecha de contratación. ¿arco, recursiva o subtipos?","Caso 4 — Los días festivos tienen tarifa especial y campañas propias. ¿La fecha se modela como atributo o como entidad (escribe: atributo / entidad_dia)?","Caso 5 — En HISTORIAL_ASIGNACION (médico ↔ consultorio a lo largo del tiempo), además de las dos relaciones, ¿qué completa el UID? (escribe una palabra)"],"initialCode":"-- HOJA DE ESTRUCTURAS — Hospital San Rafael\n\n-- Caso 1 (ejemplo): ESTUDIO_LAB se procesa en el LABORATORIO\n--   PROPIO o en uno EXTERNO (sin atributos comunes; solo uno)\ncaso1_estructura=arco\n\n-- Caso 2: MEDICO supervisado por MEDICO\ncaso2_estructura=?\n\n-- Caso 3: PERSONAL → MEDICO / ENFERMERO / OTRO\ncaso3_estructura=?\n\n-- Caso 4: festivos con tarifa especial y campañas\ncaso4_fecha=?\n\n-- Caso 5: UID de HISTORIAL_ASIGNACION =\n--   medico + consultorio + ______\ncaso5_uid_completa=?","validators":["caso2_estructura\\s*=\\s*recursiva\\b","caso3_estructura\\s*=\\s*subtipos\\b","caso4_fecha\\s*=\\s*entidad_dia\\b","caso5_uid_completa\\s*=\\s*fecha\\w*"],"mockOutput":{"columns":["CASO","ESTRUCTURA","POR QUÉ"],"rows":[["1 · ESTUDIO_LAB","arco","alternativas sin atributos comunes, exactamente una"],["2 · MEDICO–MEDICO","recursiva","la entidad consigo misma; supervisor opcional en la punta"],["3 · PERSONAL","subtipos","atributos compartidos arriba (herencia), lo propio abajo, OTRO por exhaustividad"],["4 · festivos","entidad_dia","la fecha tiene atributos propios: 3FN exige entidad DÍA"],["5 · HISTORIAL","fecha","el tiempo entra al UID: la pareja puede repetirse en fechas distintas"]],"note":"La hoja completa: cada regla compleja con su estructura correcta."},"hints":["Caso 2: la misma entidad en dos papeles (supervisor/supervisado) es la 'oreja de cerdo'.","Caso 3: comparten atributos → herencia → subtipos (con OTRO por exhaustividad). Caso 4: 'un atributo no puede tener atributos propios' → entidad_dia.","Caso 5: ¿qué permite que el mismo médico vuelva al mismo consultorio en otro período? El tiempo: fecha (o fecha_inicio) dentro del UID."],"successMessage":"Hoja de estructuras entregada: arco, recursiva, subtipos, entidad DÍA y el tiempo en el UID — las cinco herramientas avanzadas, aplicadas con criterio. El módulo de mapeo convertirá cada una en su implantación física.","failMessage":"Revisa: caso2=recursiva (la entidad consigo misma) · caso3=subtipos (herencia real + OTRO) · caso4=entidad_dia (la fecha con atributos propios) · caso5=fecha (el tiempo completa el UID)."}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm3a-l06-practica-avanzado';

-- ═════════════════════════════════════════════════════════════════════
-- X01 · Examen de región (jefe del módulo)
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"La cuarta región","body":"Byte llegó a la región de las estructuras avanzadas: once preguntas guardan el paso. Todo lo viviste: el arco que elige, la oreja de cerdo, la familia de supertipos con sus cuatro sabores, y el tiempo entrando al modelo hasta el UID. Las preguntas que falles volverán al final hasta que las domines. Adelante."}$j$),
  (2, 'quiz', $j${"variant":"multiple_choice","prompt":"Un EVENTO DE FORMACIÓN lo organiza un FORMADOR INTERNO o una COMPAÑÍA externa — exactamente uno. La estructura de modelado correcta:","options":["Subtipos de EVENTO","Un ARCO sobre las dos relaciones: OR exclusivo entre alternativas que no comparten atributos","Una relación recursiva","Una entidad DÍA"],"correctIndex":1,"feedback":{"correct":"Correcto. Alternativas excluyentes sin parentesco: el arco de manual.","incorrect":"'Uno u otro, solo uno' entre entidades sin atributos comunes = arco (OR exclusivo)."}}$j$),
  (3, 'quiz', $j${"variant":"multiple_choice","prompt":"Bajo un arco, cada relación individual es ________ y el conjunto es ________.","options":["obligatoria · opcional","OPCIONAL · exactamente-una (excluyente y conjuntamente obligatoria)","obligatoria · obligatoria","opcional · opcional"],"correctIndex":1,"feedback":{"correct":"Correcto. Cada rama puede no darse; el arco garantiza que exactamente una se dé.","incorrect":"La mecánica del arco: ramas opcionales una a una, y el arco exige exactamente una en conjunto."}}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"La diferencia entre la BARRA (|) y el ARCO en un ERD:","options":["Ninguna: son intercambiables","Barra = relación IDENTIFICADORA (entra al UID); arco = relación EXCLUYENTE (elijo una de estas): identidad vs elección","El arco es para jerarquías","La barra marca opcionalidad"],"correctIndex":1,"feedback":{"correct":"Correcto. La precisión que distingue comprensión de memorización.","incorrect":"Barra: 'te necesito para mi identidad'. Arco: 'elijo exactamente una'. Reglas distintas, símbolos distintos."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"'EMPLEADO es gestionado por EMPLEADO' se dibuja con una línea que sale y vuelve a la misma caja. Nombre y exigencia técnica:","options":["Jerarquía; todos con jefe","Relación RECURSIVA ('oreja de cerdo'); la relación debe ser OPCIONAL — la punta de la pirámide no tiene jefe","Arco; una CHECK","Subtipo; discriminador"],"correctIndex":1,"feedback":{"correct":"Correcto. Recursiva flexible… con su cima sin superior: jefe_id nace opcional.","incorrect":"La entidad consigo misma = recursiva; y exige opcionalidad en la punta (¿quién es el jefe de la directora general?)."}}$j$),
  (6, 'quiz', $j${"variant":"multiple_choice","prompt":"Una jerarquía EXPLÍCITA (una entidad por nivel) se prefiere a la recursiva cuando…","options":["Los niveles cambian cada mes","Los niveles son POCOS, FIJOS y con atributos genuinamente DISTINTOS por nivel","Hay más de mil empleados","Nunca se prefiere"],"correctIndex":1,"feedback":{"correct":"Correcto. Especificidad a cambio de rigidez: vale la pena solo si los niveles no se mueven y difieren de verdad.","incorrect":"Explícita = específica pero rígida: para niveles fijos y distintos. Variables y de la misma especie → recursiva."}}$j$),
  (7, 'quiz', $j${"variant":"multiple_choice","prompt":"PERSONAL (nombre, fecha_contratacion) con subtipos MEDICO (colegiatura) y ENFERMERO (turno). ¿Qué garantiza la HERENCIA?","options":["Que los subtipos comparten colegiatura","Que MEDICO y ENFERMERO tienen automáticamente nombre y fecha_contratacion: lo del supertipo pertenece a cada subtipo","Que PERSONAL tiene turno","Que los subtipos comparten UID entre sí"],"correctIndex":1,"feedback":{"correct":"Correcto. Lo común se declara una vez arriba y baja gratis a cada subtipo.","incorrect":"La herencia baja del supertipo a los subtipos: todo médico ES un personal, con sus atributos incluidos."}}$j$),
  (8, 'quiz', $j${"variant":"multiple_choice","prompt":"Los cuatro sabores que un diseño de subtipos debe declarar:","options":["Rápido/lento × grande/pequeño","TOTAL/PARCIAL (¿toda instancia cae en un subtipo?) × DISJUNTO/SUPERPUESTO (¿solo en uno a la vez?)","1FN/2FN × 3FN/BCNF","Interno/externo × público/privado"],"correctIndex":1,"feedback":{"correct":"Correcto. Y declarar el sabor es una regla de negocio: el alumno-empleado existe (superposición) y el mapeo lo cobra.","incorrect":"Exhaustividad (total/parcial) y exclusividad (disjunto/superpuesto): los dos ejes, cuatro combinaciones."}}$j$),
  (9, 'quiz', $j${"variant":"multiple_choice","prompt":"Registrar el valor VIEJO de un dato, con su momento, antes de modificarlo — para poder auditar y reconstruir — se llama…","options":["Indexación","Anotación en diario (LOGGING/JOURNALING): la materia prima de la auditoría","Normalización","Truncado"],"correctIndex":1,"feedback":{"correct":"Correcto. Sin el diario, el pasado se pisa y las decisiones quedan sin contexto reconstruible.","incorrect":"El registro cronológico de valores previos es el logging/journaling del modelado temporal."}}$j$),
  (10, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Cuándo la fecha deja de ser atributo y se convierte en entidad DÍA?","options":["Cuando hay muchas fechas","Cuando la fecha tiene ATRIBUTOS PROPIOS (festivo, tarifa, campaña): la 3FN — 'un atributo no puede tener atributos propios' — la asciende a entidad","Cuando el año es bisiesto","Nunca: las fechas son siempre atributos"],"correctIndex":1,"feedback":{"correct":"Correcto. La 3FN del módulo pasado, decidiendo diseño temporal: la fecha con vida propia es DÍA.","incorrect":"El criterio es 3FN: si la fecha carga atributos propios, es una entidad DÍA disfrazada."}}$j$),
  (11, 'quiz', $j${"variant":"multiple_choice","prompt":"En HISTORIAL_PRECIO de un producto, el UID es producto + fecha_inicio. ¿Qué permitiría ese diseño que un UID de solo producto prohibiría?","options":["Guardar el precio actual","Que el producto acumule MUCHOS períodos de precio — incluso volver a un precio anterior en fechas distintas: el tiempo en el UID habilita la historia","Borrar precios viejos","Nada: son equivalentes"],"correctIndex":1,"feedback":{"correct":"Correcto. Sin la fecha en el UID, el segundo período sería un 'duplicado' imposible: la historia exige el tiempo en la identidad.","incorrect":"El tiempo en el UID es lo que permite la repetición legítima: muchos períodos por producto, cada uno único por su fecha."}}$j$),
  (12, 'quiz', $j${"variant":"multiple_choice","prompt":"Pregunta final de entrevista: 'modelamos PERSONAL con subtipos MEDICO y ENFERMERO, pero también necesitamos que un estudio se procese en laboratorio propio O externo. ¿Por qué una estructura para cada caso?' Tu respuesta senior:","options":["Por variedad estética","Porque los criterios difieren: médicos y enfermeros COMPARTEN atributos (herencia real → subtipos, con OTRO por exhaustividad); los laboratorios alternativos NO comparten nada significativo y la regla es 'exactamente uno' (→ arco, OR exclusivo). La estructura sigue a la semántica, no a la moda","Porque los subtipos son para personas y los arcos para cosas","Da igual cuál se use"],"correctIndex":1,"feedback":{"correct":"Impecable. Herencia real → subtipos; alternativas sin parentesco → arco. La estructura sigue a la semántica: así se defiende un modelo.","incorrect":"La respuesta senior compara criterios: atributos compartidos piden supertipo (herencia); alternativas ajenas con 'exactamente uno' piden arco."}}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm3a-x01-examen';
